A `rewrites()` or `redirects()` rule that builds its external destination hostname from request-controlled input can be pointed at an arbitrary hostname, regardless of the rule's hostname suffix. For a rewrite, Next.js proxies the request to that arbitrary host and serves the response from the application's origin, leading to Server-Side Request forgery. A `redirects()` rule configured this way is vulnerable to an Open Redirect.

This affects any destination that puts a dynamic segment in the hostname, whether from the path:

```javascript
// next.config.js
module.exports = {
  async rewrites() {
    return [
      {
        source: '/:tenant',
        destination: 'https://:tenant.api.example.com',
      },
    ]
  },
}
```

or from a `has` capture:

```javascript
// next.config.js
module.exports = {
  async rewrites() {
    return [
      {
        source: '/',
        has: [{ type: 'query', key: 'region', value: '(?<region>.+)' }],
        destination: 'https://:region.api.example.com',
      },
    ]
  },
}
```

## Workarounds

If you cannot upgrade immediately, do not build the hostname of an external `rewrites()` or `redirects()` destination from user-controlled input. If a dynamic subdomain is required, constrain the value to hostname-safe characters:  `value: '(?<region>[a-z0-9-]+)'`.", "ghsa_id": "GHSA-p9j2-gv94-2wf4", "html_url": "https://github.com/vercel/next.js/security/advisories/GHSA-p9j2-gv94-2wf4", "identifiers": [{"type": "GHSA", "value": "GHSA-p9j2-gv94-2wf4"}, {"type": "CVE", "value": "CVE-2026-64645"}], "private_fork": null, "published_at": "2026-07-21T16:02:54Z", "publisher": {"avatar_url": "https://avatars.githubusercontent.com/u/14217083?v=4", "events_url": "https://api.github.com/users/KarimPwnz/events{/privacy}", "followers_url": "https://api.github.com/users/KarimPwnz/followers", "following_url": "https://api.github.com/users/KarimPwnz/following{/other_user}", "gists_url": "https://api.github.com/users/KarimPwnz/gists{/gist_id}", "gravatar_id": "", "html_url": "https://github.com/KarimPwnz", "id": 14217083, "login": "KarimPwnz", "node_id": "MDQ6VXNlcjE0MjE3MDgz", "organizations_url": "https://api.github.com/users/KarimPwnz/orgs", "received_events_url": "https://api.github.com/users/KarimPwnz/received_events", "repos_url": "https://api.github.com/users/KarimPwnz/repos", "site_admin": false, "starred_url": "https://api.github.com/users/KarimPwnz/starred{/owner}{/repo}", "subscriptions_url": "https://api.github.com/users/KarimPwnz/subscriptions", "type": "User", "url": "https://api.github.com/users/KarimPwnz", "user_view_type": "public"}, "severity": "high", "state": "published", "submission": null, "summary": "Server-Side Request Forgery in rewrites via attacker-controlled destination hostname", "updated_at": "2026-07-21T16:02:54Z", "url": "https://api.github.com/repos/vercel/next.js/security-advisories/GHSA-p9j2-gv94-2wf4", "vulnerabilities": [{"package": {"ecosystem": "npm", "name": "next"}, "patched_versions": "15.5.21", "vulnerable_functions": [], "vulnerable_versi